from vimms.ChemicalSamplers.DatabaseFormulaSampler import DatabaseFormulaSampler; from vimms.MassSpecIonisation import EI; import pickle; import zipfile; import os; db_path = '{inputs.hmdb_database}'; db = None; db_name = os.path.basename(db_path).lower(); print(f'Loading HMDB database from {db_path}'); filtered_formulas = set(); try:
    if db_name.endswith('.zip'):
        with zipfile.ZipFile(db_path, 'r') as z:
            for name in z.namelist():
                if 'hmdb' in name.lower() and name.endswith('.p'):
                    with z.open(name) as f:
                        db = pickle.load(f)
                    break
    elif db_name.endswith('.p'):
        with open(db_path, 'rb') as f:
            db = pickle.load(f)
    if db is None:
        raise ValueError('Could not load HMDB database')
    sampler = DatabaseFormulaSampler(db, ionisation_mode=EI())
    filtered_formulas = set(sampler.sample(len(db)) if hasattr(sampler, 'sample') else [m.formula for m in db if hasattr(m, 'formula')])
    unique_count = len(filtered_formulas)
    print(f'Filtered unique formulas count: {unique_count}')
    if unique_count == 73822:
        print('VALIDATION PASSED: Formula count matches expected 73,822')
    else:
        print(f'VALIDATION WARNING: Expected 73,822 but got {unique_count}')
except Exception as e:
    print(f'Error: {e}')
    raise
